const item = $input.first().json;
const req = (item.userRequest || item.studyContent || '').toLowerCase();

let intent = 'process'; // default: just uploaded a PDF or pasted text

if (req.includes('quiz') || req.includes('test me') || req.includes('question me')) {
  intent = 'quiz';
} else if (req.includes('flashcard') || req.includes('flash card') || req.includes('key terms') || req.includes('key concepts')) {
  intent = 'flashcards';
} else if (req.includes('revision plan') || req.includes('study plan') || req.includes('schedule') || req.includes('plan')) {
  intent = 'revision_plan';
} else if (req.includes('summarize') || req.includes('summary') || req.includes('explain') || req.includes('what is') || req.includes('help me understand')) {
  intent = 'explain';
}

return {
  studyContent: item.studyContent,
  userRequest: item.userRequest,
  inputSource: item.inputSource,
  intent
};
